   816→                    disabled={!team.teamPlan}
   817→                    onClick={() => {
   818→                      setTeamItemDistributionModalParam({
   819→                        isOpen: true,
   820→                        team,
   821→                      });
   822→                      closeMenu();
   823→                    }}
   824→                  >
   825→                    {translate('item_distribution')}
   826→                  </MenuItem>
   827→                  <MenuItem
   828→                    disabled={!team.teamPlan}
   829→                    onClick={() => {
   830→                      setEditCurrentOrPreviousTeamPlanModalParam(
   831→                        {
   832→                          isOpen: true,
   833→                          team,
   834→                          title:
   835→                            editCurrentOrPreviousTeamPlanModalTitle,
   836→                        },
   837→                      );
   838→                      closeMenu();
   839→                    }}
   840→                  >
   841→                    {editCurrentOrPreviousTeamPlanModalTitle}
   842→                  </MenuItem>
   843→                  {team.nextTeamPlan ? (
   844→                    <MenuItem
   845→                      onClick={() => {
   846→                        setEditOrDeleteNextTeamPlanModalParam(
   847→                          {
   848→                            isOpen: true,
   849→                            team,
   850→                          },
   851→                        );
   852→                        closeMenu();
   853→                      }}
   854→                    >
   855→                      {translate(
   856→                        'edit_or_delete_next_team_plan',
   857→                      )}
   858→                    </MenuItem>
   859→                  ) : (
   860→                    <MenuItem
   861→                      onClick={() => {
   862→                        setCreateTeamPlanModalParam({
   863→                          isOpen: true,
   864→                          team,
   865→                          title: createTeamPlanModalTitle,
   866→                        });
   867→                        closeMenu();
   868→                      }}
   869→                    >
   870→                      {createTeamPlanModalTitle}
   871→                    </MenuItem>
   872→                  )}
   873→                  <MenuItem
   874→                    onClick={() => {
   875→                      dispatch(
   876→                        userDataActions.setCurrentTeam({
   877→                          teamId: team.id,
   878→                        }),
   879→                      );
   880→
   881→                      services.localStorage.setCurrentTeamId(currentUser.id, team.id);
   882→
   883→                      enqueueSnackbar({
   884→                        variant: 'success',
   885→                        message: translate('snackbar_change_current_team'),
   886→                      });
   887→
   888→                      closeMenu();
   889→                    }}
   890→                  >
   891→                    {translate('switch_team')}
   892→                  </MenuItem>
   893→                </>
   894→              ) : (
   895→                <></>
   896→              )}
   897→            </>
   898→          );
   899→        })()
   900→      )}
   901→    </Menu>;
   902→
   903→  return (
   904→    // mbはFABのため
   905→    <Container sx={{ position: 'relative', mb: 10 }}>
   906→      <TeamCreationModal
   907→        param={teamCreationParam}
   908→        setParam={setTeamCreationParam}
   909→        isOpen={isCreationModalOpen}
   910→        setIsOpen={setIsCreationModalOpen}
   911→        onSuccess={() => {
   912→          setConditions({
   913→            ...conditions,
   914→            searchTrigger: new Date(),
   915→          });
   916→        }}
   917→      />
   918→      <EditCurrentOrPreviousTeamPlanModal
   919→        teamId={editCurrentOrPreviousTeamPlanModalParam.team?.id ?? null}
   920→        teamPlan={
   921→          editCurrentOrPreviousTeamPlanModalParam.team?.teamPlan ?? null
   922→        }
   923→        title={editCurrentOrPreviousTeamPlanModalParam.title}
   924→        isOpen={editCurrentOrPreviousTeamPlanModalParam.isOpen}
   925→        setIsOpen={(isOpen) =>
   926→          setEditCurrentOrPreviousTeamPlanModalParam((current) => ({
   927→            ...current,
   928→            isOpen: isOpen as boolean,
   929→          }))
   930→        }
   931→        onSuccess={getTeams}
   932→      />
   933→      <CreateTeamPlanModal
   934→        teamId={createTeamPlanModalParam.team?.id ?? null}
   935→        defaultDate={createTeamPlanModalParam.team?.teamPlan?.endDate ?? null}
   936→        title={createTeamPlanModalParam.title}
   937→        isOpen={createTeamPlanModalParam.isOpen}
   938→        setIsOpen={(isOpen) =>
   939→          setCreateTeamPlanModalParam((current) => ({
   940→            ...current,
   941→            isOpen: isOpen as boolean,
   942→          }))
   943→        }
   944→        onSuccess={getTeams}
   945→      />
   946→      <EditOrDeleteNextTeamPlanModal
   947→        teamId={editOrDeleteNextTeamPlanModalParam.team?.id ?? null}
   948→        teamPlan={editOrDeleteNextTeamPlanModalParam.team?.nextTeamPlan ?? null}
   949→        isOpen={editOrDeleteNextTeamPlanModalParam.isOpen}
   950→        setIsOpen={(isOpen) =>
   951→          setEditOrDeleteNextTeamPlanModalParam((current) => ({
   952→            ...current,
   953→            isOpen: isOpen as boolean,
   954→          }))
   955→        }
   956→        onSuccess={getTeams}
   957→      />
   958→      <ConfirmationModal
   959→        isOpen={confirmModalIsOpen}
   960→        setIsOpen={setConfirmModalIsOpen}
   961→        {...confirmModal}
   962→        onClose={() => {
   963→          setConfirmModalIsOpen(false);
   964→          setConfirmModal({});
   965→        }}
   966→      />
   967→      <TeamItemDistributionModal
   968→        isOpen={teamItemDistributionModalParam.isOpen}
   969→        setIsOpen={(isOpen) =>
   970→          setTeamItemDistributionModalParam((current) => ({
   971→            ...current,
   972→            isOpen: isOpen as boolean,
   973→          }))
   974→        }
   975→        team={teamItemDistributionModalParam.team}
   976→        hasSuperUserWriteAccess={hasSuperUserWriteAccess}
   977→        onDistributed={getTeams}
   978→      />
   979→
   980→      <DefaultBreadCrumbs
   981→        breadcrumbs={[
   982→          {
   983→            name: translate(
   984→              PAGE_INFO.SUPER_ADMIN_TEAMS.name as keyof typeof translate,
   985→            ),
   986→            link: PAGE_INFO.SUPER_ADMIN_TEAMS.href(),
   987→          },
   988→        ]}
   989→      />
   990→      <Typography variant="h1">{translate('all_teams')}</Typography>
   991→      <Divider sx={{ mt: 1, mb: 5 }} />
   992→
   993→      <Card sx={{ backgroundColor: 'white', p: 2 }}>
   994→        {buildSearchAndFilterArea()}
   995→
   996→        {loadError ? (
   997→          <CriticalError error={loadError} />
   998→        ) : (
   999→          <>
  1000→            <Box sx={{ mb: 2, mt: 2 }}>
  1001→              <Stack direction="row" spacing={2}>
  1002→                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
  1003→                  <Box
  1004→                    sx={{
  1005→                      width: 20,
  1006→                      height: 20,
  1007→                      backgroundColor: 'gray',
  1008→                      border: '1px solid #ccc',
  1009→                    }}
  1010→                  />
  1011→                  <Typography variant="body2">
  1012→                    {translate('team_list_legend_deletion_scheduled')}
  1013→                  </Typography>
  1014→                </Box>
  1015→                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
  1016→                  <Box
  1017→                    sx={{
  1018→                      width: 20,
  1019→                      height: 20,
  1020→                      backgroundColor: '#fff3e0',
  1021→                      border: '1px solid #ccc',
  1022→                    }}
  1023→                  />
  1024→                  <Typography variant="body2">
  1025→                    {translate('team_list_legend_no_quota')}
  1026→                  </Typography>
  1027→                </Box>
  1028→              </Stack>
  1029→            </Box>
  1030→            <TableContainer component={Paper}>
  1031→            <Table
  1032→              sx={{
  1033→                tableLayout: 'fixed',
  1034→                '.MuiTableCell-root': { overflowWrap: 'anywhere' },
  1035→              }}
  1036→            >
  1037→              <TableHead>
  1038→                <TableRow>
  1039→                  <TableCell align="left">ID</TableCell>
  1040→                  <TableCell align="left">{translate('team_name')}</TableCell>
  1041→                  <TableCell align="left">{translate('plan')}</TableCell>
  1042→                  <TableCell align="left" sx={{ width: '25%' }}>{translate('usage')}</TableCell>
  1043→                  <TableCell align="left">{translate('start_end')}</TableCell>
  1044→                  <TableCell align="left" sx={{ width: '18%' }}>
  1045→                    {translate('num_users_and_users')}
  1046→                  </TableCell>
  1047→                  <TableCell sx={{ width: '5rem' }} />
  1048→                </TableRow>
  1049→              </TableHead>
  1050→              <TableBody>
  1051→                {teams.map(buildTeamRow)}
  1052→              </TableBody>
  1053→            </Table>
  1054→          </TableContainer>
  1055→          </>
  1056→        )}
  1057→
  1058→        <CommonPagination
  1059→          user={currentUser}
  1060→          numberOfTotalItems={numberOfTotalItems}
  1061→          commonPaginationData={{
  1062→            currentPage: conditions.currentPage,
  1063→            rowsPerPage: conditions.rowsPerPage,
  1064→          }}
  1065→          onChange={(data) => {
  1066→            updateQueryParameters({
  1067→              ...conditions,
  1068→              ...data,
  1069→            });
  1070→          }}
  1071→        />
  1072→      </Card>
  1073→
  1074→      {hasSuperUserWriteAccess && (
  1075→        <FloatingButton
  1076→          icon={<PersonAddAlt />}
  1077→          title={translate('create_new_team')}
  1078→          onClick={() => setIsCreationModalOpen(true)}
  1079→        />
  1080→      )}
  1081→    </Container>
  1082→  );
  1083→}
  1084→
  1085→export default function Page() {
  1086→  const currentUser = useSelector((state) => state.user.me);
  1087→  const currentTeam = useSelector((state) => state.user.currentTeam);
  1088→  return (
  1089→    currentUser &&
  1090→    currentTeam && (
  1091→      <PageInner currentUser={currentUser} currentTeam={currentTeam} />
  1092→    )
