// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/super_admin_team_search_controller.dart';
import 'package:baseball_detector_flutter/data/models/dto/team/team_search_request.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';

/// A bottom sheet for advanced team search filters.
class SuperAdminTeamFilterSheet extends ConsumerWidget {
  const SuperAdminTeamFilterSheet({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final params = ref.watch(teamSearchFilterParametersNotifierProvider);

    return DraggableScrollableSheet(
      initialChildSize: 0.9,
      minChildSize: 0.5,
      maxChildSize: 0.95,
      expand: false,
      builder: (context, scrollController) {
        return Container(
          decoration: BoxDecoration(
            color: theme.colorScheme.surface,
            borderRadius: const BorderRadius.vertical(top: Radius.circular(16)),
          ),
          child: Column(
            children: [
              // Handle
              Container(
                margin: const EdgeInsets.symmetric(vertical: 12),
                width: 40,
                height: 4,
                decoration: BoxDecoration(
                  color: theme.colorScheme.onSurfaceVariant.withOpacity(0.4),
                  borderRadius: BorderRadius.circular(2),
                ),
              ),
              // Title
              Padding(
                padding: const EdgeInsets.symmetric(horizontal: 16),
                child: Row(
                  children: [
                    Expanded(
                      child: Text(
                        context.l10n.super_admin_team_filter__title,
                        style: theme.textTheme.titleLarge,
                      ),
                    ),
                    TextButton(
                      onPressed: () {
                        ref
                            .read(teamSearchFilterParametersNotifierProvider
                                .notifier)
                            .clearFilters();
                        Navigator.pop(context);
                      },
                      child: Text(context.l10n.super_admin_team_filter__reset),
                    ),
                  ],
                ),
              ),
              const Divider(),
              // Filter content
              Expanded(
                child: ListView(
                  controller: scrollController,
                  padding: const EdgeInsets.all(16),
                  children: [
                    _buildSortSection(context, ref, theme, params),
                    const Gap(24),
                    _buildTeamTypeSection(context, ref, theme, params),
                    const Gap(24),
                    _buildStatusSection(context, ref, theme, params),
                    const Gap(24),
                    _buildPlanSection(context, ref, theme, params),
                    const Gap(24),
                    _buildExpirySection(context, ref, theme, params),
                  ],
                ),
              ),
              // Apply button
              SafeArea(
                child: Padding(
                  padding: const EdgeInsets.all(16),
                  child: SizedBox(
                    width: double.infinity,
                    child: FilledButton(
                      onPressed: () => Navigator.pop(context),
                      child: Text(context.l10n.super_admin_team_filter__apply),
                    ),
                  ),
                ),
              ),
            ],
          ),
        );
      },
    );
  }

  Widget _buildSortSection(
    BuildContext context,
    WidgetRef ref,
    ThemeData theme,
    TeamSearchFilterParameters params,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__sort,
          style: theme.textTheme.titleSmall,
        ),
        const Gap(12),
        _buildSortOption(
          context,
          ref,
          context.l10n.super_admin_team_filter__sort_newest,
          TeamSearchRequestOrderBy.createdAt,
          true,
          params.orderBy == TeamSearchRequestOrderBy.createdAt &&
              params.isOrderDesc == true,
        ),
        _buildSortOption(
          context,
          ref,
          context.l10n.super_admin_team_filter__sort_oldest,
          TeamSearchRequestOrderBy.createdAt,
          false,
          params.orderBy == TeamSearchRequestOrderBy.createdAt &&
              params.isOrderDesc == false,
        ),
        _buildSortOption(
          context,
          ref,
          context.l10n.super_admin_team_filter__sort_plan_start_asc,
          TeamSearchRequestOrderBy.teamPlanStartDate,
          false,
          params.orderBy == TeamSearchRequestOrderBy.teamPlanStartDate &&
              params.isOrderDesc == false,
        ),
        _buildSortOption(
          context,
          ref,
          context.l10n.super_admin_team_filter__sort_plan_start_desc,
          TeamSearchRequestOrderBy.teamPlanStartDate,
          true,
          params.orderBy == TeamSearchRequestOrderBy.teamPlanStartDate &&
              params.isOrderDesc == true,
        ),
        _buildSortOption(
          context,
          ref,
          context.l10n.super_admin_team_filter__sort_plan_end_asc,
          TeamSearchRequestOrderBy.teamPlanEndDate,
          false,
          params.orderBy == TeamSearchRequestOrderBy.teamPlanEndDate &&
              params.isOrderDesc == false,
        ),
        _buildSortOption(
          context,
          ref,
          context.l10n.super_admin_team_filter__sort_plan_end_desc,
          TeamSearchRequestOrderBy.teamPlanEndDate,
          true,
          params.orderBy == TeamSearchRequestOrderBy.teamPlanEndDate &&
              params.isOrderDesc == true,
        ),
      ],
    );
  }

  Widget _buildSortOption(
    BuildContext context,
    WidgetRef ref,
    String label,
    TeamSearchRequestOrderBy orderBy,
    bool isDesc,
    bool isSelected,
  ) {
    return RadioListTile<bool>(
      title: Text(label),
      value: true,
      groupValue: isSelected,
      onChanged: (_) {
        ref
            .read(teamSearchFilterParametersNotifierProvider.notifier)
            .updateOrderBy(orderBy, isDesc);
      },
      contentPadding: EdgeInsets.zero,
      dense: true,
    );
  }

  Widget _buildTeamTypeSection(
    BuildContext context,
    WidgetRef ref,
    ThemeData theme,
    TeamSearchFilterParameters params,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__team_type,
          style: theme.textTheme.titleSmall,
        ),
        const Gap(12),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__all),
              selected: params.teamTypes == null || params.teamTypes!.isEmpty,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(teamTypes: null);
              },
            ),
            FilterChip(
              label: Text(context.l10n.team_type__single),
              selected: params.teamTypes?.contains(TeamType.single) ?? false,
              onSelected: (selected) {
                final newTypes = selected ? [TeamType.single] : <TeamType>[];
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(teamTypes: newTypes.isEmpty ? null : newTypes);
              },
            ),
            FilterChip(
              label: Text(context.l10n.team_type__multiple),
              selected: params.teamTypes?.contains(TeamType.multiple) ?? false,
              onSelected: (selected) {
                final newTypes =
                    selected ? [TeamType.multiple] : <TeamType>[];
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(teamTypes: newTypes.isEmpty ? null : newTypes);
              },
            ),
          ],
        ),
      ],
    );
  }

  Widget _buildStatusSection(
    BuildContext context,
    WidgetRef ref,
    ThemeData theme,
    TeamSearchFilterParameters params,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__status,
          style: theme.textTheme.titleSmall,
        ),
        const Gap(12),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__all),
              selected: params.isDeletionScheduled == null,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(isDeletionScheduled: null);
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__status_active),
              selected: params.isDeletionScheduled == false,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(isDeletionScheduled: false);
              },
            ),
            FilterChip(
              label: Text(
                  context.l10n.super_admin_team_filter__status_deletion_scheduled),
              selected: params.isDeletionScheduled == true,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(isDeletionScheduled: true);
              },
            ),
          ],
        ),
      ],
    );
  }

  Widget _buildPlanSection(
    BuildContext context,
    WidgetRef ref,
    ThemeData theme,
    TeamSearchFilterParameters params,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__plan,
          style: theme.textTheme.titleSmall,
        ),
        const Gap(12),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__all),
              selected: params.isPlanPaid == null,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(isPlanPaid: null);
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__plan_free),
              selected: params.isPlanPaid == false,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(isPlanPaid: false);
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__plan_paid),
              selected: params.isPlanPaid == true,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(isPlanPaid: true);
              },
            ),
          ],
        ),
      ],
    );
  }

  Widget _buildExpirySection(
    BuildContext context,
    WidgetRef ref,
    ThemeData theme,
    TeamSearchFilterParameters params,
  ) {
    final now = DateTime.now();
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__expiry,
          style: theme.textTheme.titleSmall,
        ),
        const Gap(12),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__all),
              selected: params.teamPlanEndDateFrom == null &&
                  params.teamPlanEndDateTo == null,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(
                      teamPlanEndDateFrom: null,
                      teamPlanEndDateTo: null,
                    );
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__expiry_1week),
              selected: _isExpiryFilterSelected(
                params,
                now,
                now.add(const Duration(days: 7)),
              ),
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(
                      teamPlanEndDateFrom: now,
                      teamPlanEndDateTo: now.add(const Duration(days: 7)),
                    );
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__expiry_2weeks),
              selected: _isExpiryFilterSelected(
                params,
                now,
                now.add(const Duration(days: 14)),
              ),
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(
                      teamPlanEndDateFrom: now,
                      teamPlanEndDateTo: now.add(const Duration(days: 14)),
                    );
              },
            ),
          ],
        ),
        if (params.orderBy == TeamSearchRequestOrderBy.teamPlanEndDate ||
            params.teamPlanEndDateFrom != null ||
            params.teamPlanEndDateTo != null) ...[
          const Gap(12),
          SwitchListTile(
            title: Text(context.l10n.super_admin_team_filter__include_next_plan),
            value: params.extendToNextTeamPlan ?? false,
            onChanged: (value) {
              ref
                  .read(teamSearchFilterParametersNotifierProvider.notifier)
                  .updateFilters(extendToNextTeamPlan: value);
            },
            contentPadding: EdgeInsets.zero,
            dense: true,
          ),
        ],
      ],
    );
  }

  bool _isExpiryFilterSelected(
    TeamSearchFilterParameters params,
    DateTime from,
    DateTime to,
  ) {
    if (params.teamPlanEndDateFrom == null || params.teamPlanEndDateTo == null) {
      return false;
    }
    return params.teamPlanEndDateFrom!.isAtSameMomentAs(from) &&
        params.teamPlanEndDateTo!.isAtSameMomentAs(to);
  }
}

