  Widget _buildExpirySection(
    BuildContext context,
    WidgetRef ref,
    ThemeData theme,
    TeamSearchFilterParameters params,
  ) {
    final now = DateTime.now();
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__expiry,
          style: theme.textTheme.titleSmall,
        ),
        const Gap(12),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__all),
              selected: params.teamPlanEndDateFrom == null &&
                  params.teamPlanEndDateTo == null,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(
                      teamPlanEndDateFrom: null,
                      teamPlanEndDateTo: null,
                    );
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__expiry_1week),
              selected: _isExpiryFilterSelected(
                params,
                now,
                now.add(const Duration(days: 7)),
              ),
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(
                      teamPlanEndDateFrom: now,
                      teamPlanEndDateTo: now.add(const Duration(days: 7)),
                    );
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__expiry_2weeks),
              selected: _isExpiryFilterSelected(
                params,
                now,
                now.add(const Duration(days: 14)),
              ),
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(
                      teamPlanEndDateFrom: now,
                      teamPlanEndDateTo: now.add(const Duration(days: 14)),
                    );
              },
            ),
          ],
        ),
        if (params.orderBy == TeamSearchRequestOrderBy.teamPlanEndDate ||
            params.teamPlanEndDateFrom != null ||
            params.teamPlanEndDateTo != null) ...[
          const Gap(12),
          SwitchListTile(
            title: Text(context.l10n.super_admin_team_filter__include_next_plan),
            value: params.extendToNextTeamPlan ?? false,
            onChanged: (value) {
              ref
                  .read(teamSearchFilterParametersNotifierProvider.notifier)
                  .updateFilters(extendToNextTeamPlan: value);
            },
            contentPadding: EdgeInsets.zero,
            dense: true,
          ),
        ],
      ],
    );
  }

  bool _isExpiryFilterSelected(
    TeamSearchFilterParameters params,
    DateTime from,
    DateTime to,
  ) {
    if (params.teamPlanEndDateFrom == null || params.teamPlanEndDateTo == null) {
      return false;
    }
    return params.teamPlanEndDateFrom!.isAtSameMomentAs(from) &&
        params.teamPlanEndDateTo!.isAtSameMomentAs(to);
  }
}

