                        .l10n.super_admin_team_switcher__search_hint_owner_email,
                prefixIcon: Icon(Icons.search, color: colorScheme.primary),
                suffixIcon: IconButton(
                  icon: const Icon(Icons.clear),
                  onPressed: () {
                    controller.clear();
                    performSearch();
                  },
                ),
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(12),
                ),
              ),
            ),
          ],
          const Gap(8),
          SegmentedButton<TeamSearchType>(
            segments: [
              ButtonSegment<TeamSearchType>(
                value: TeamSearchType.teamName,
                label: Text(context
                    .l10n.super_admin_team_switcher__search_type_team_name),
                icon: const Icon(Icons.badge),
              ),
              ButtonSegment<TeamSearchType>(
                value: TeamSearchType.ownerEmail,
                label: Text(context
                    .l10n.super_admin_team_switcher__search_type_owner_email),
                icon: const Icon(Icons.email),
              ),
              ButtonSegment<TeamSearchType>(
                value: TeamSearchType.teamType,
                label: Text(context
                    .l10n.super_admin_team_switcher__search_type_team_type),
                icon: const Icon(Icons.category),
              ),
            ],
            selected: {searchType.value},
            onSelectionChanged: (Set<TeamSearchType> newSelection) {
              searchType.value = newSelection.first;
              // 検索タイプ切り替え時にテキストと teamType をクリア
              controller.clear();
              selectedTeamTypes.value = [];
              // 検索タイプ変更時にも検索を実行してリセット
              performSearch();
            },
          ),
        ],
      ),
    );
  }
}

